def icon_button(icon: str, tooltip: str) -> Gtk.Button:
    button = Gtk.Button.new_from_icon_name(icon)
    button.set_tooltip_text(tooltip)
    button.add_css_class("flat")
    button.add_css_class("nav-button")
    return button


class TrowserWindow(Gtk.ApplicationWindow):
    def __init__(self, app: Gtk.Application) -> None:
        super().__init__(application=app, title="Trowser")
        self.set_default_size(1280, 820)
        self.store = BrowserStore()
        self.ollama = OllamaClient()
        self.account_client = TailsAccountClient()
        self.vault = PasswordVault()
        self.focus_mode = False
        self.account_name: str | None = None

        self._build_ui()
        self._install_shortcuts()
        self.new_tab()

    def _build_ui(self) -> None:
        root = Gtk.Box(orientation=Gtk.Orientation.VERTICAL)
        self.set_child(root)

        self.toolbar = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=4)
        self.toolbar.add_css_class("toolbar")
        root.append(self.toolbar)

        self.back = icon_button("go-previous-symbolic", "Back")
        self.forward = icon_button("go-next-symbolic", "Forward")
        self.reload = icon_button("view-refresh-symbolic", "Reload")
        self.home = icon_button("go-home-symbolic", "Home")
        for button in (self.back, self.forward, self.reload, self.home):
            self.toolbar.append(button)

        self.address = Gtk.Entry()
        self.address.set_hexpand(True)
        self.address.set_placeholder_text("Search or enter an address")
        self.address.add_css_class("address")
        self.toolbar.append(self.address)

        self.bookmark = icon_button("non-starred-symbolic", "Toggle bookmark")
        self.ai_button = icon_button("system-run-symbolic", "Ask Ollama")
        self.library = icon_button("view-list-symbolic", "Bookmarks and history")
        self.settings_button = icon_button("preferences-system-symbolic", "Settings")
        self.account = Gtk.MenuButton(icon_name="avatar-default-symbolic")
        self.account.set_tooltip_text("tails1154 account")
        self.account.add_css_class("flat")
        self.account.set_popover(self._account_popover())
        for button in (
            self.bookmark,
            self.ai_button,
            self.library,
            self.settings_button,
            self.account,
        ):
            self.toolbar.append(button)

        content = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL)
        content.set_vexpand(True)
        root.append(content)

        self.notebook = Gtk.Notebook()
        self.notebook.set_scrollable(True)
        self.notebook.set_hexpand(True)
        self.notebook.set_vexpand(True)
        content.append(self.notebook)

        self.sidebar = Gtk.Revealer()
        self.sidebar.set_transition_type(Gtk.RevealerTransitionType.SLIDE_LEFT)
        self.sidebar.set_transition_duration(180)
        self.sidebar.set_visible(False)
        self.sidebar.connect("notify::child-revealed", self._sidebar_transition_done)
        self.sidebar_box = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=12)
        self.sidebar_box.set_size_request(360, -1)
        self.sidebar_box.set_margin_top(16)
        self.sidebar_box.set_margin_bottom(16)
        self.sidebar_box.set_margin_start(16)
        self.sidebar_box.set_margin_end(16)
        self.sidebar_box.add_css_class("sidebar")
        self.sidebar.set_child(self.sidebar_box)
        content.append(self.sidebar)

        self.back.connect("clicked", lambda *_: self.current_view().go_back())
        self.forward.connect("clicked", lambda *_: self.current_view().go_forward())
        self.reload.connect("clicked", lambda *_: self.current_view().reload())
        self.home.connect("clicked", lambda *_: self.load("trowser://homepage"))
        self.address.connect("activate", self._address_activated)
        self.bookmark.connect("clicked", lambda *_: self.toggle_bookmark())
        self.ai_button.connect("clicked", lambda *_: self.show_ai())
        self.library.connect("clicked", lambda *_: self.show_bookmarks())
        self.settings_button.connect("clicked", lambda *_: self.show_settings())
        self.notebook.connect("switch-page", self._tab_switched)
        self.connect("close-request", self._on_close)

    def _account_popover(self) -> Gtk.Popover:
        popover = Gtk.Popover()
        box = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=8)
        box.set_size_request(280, -1)
        box.set_margin_top(18)
        box.set_margin_bottom(18)
        box.set_margin_start(18)
        box.set_margin_end(18)
        title = Gtk.Label(label="tails1154 account")
        title.add_css_class("title-3")
        subtitle = Gtk.Label(label="Sign in to tails1154.com", xalign=0)
        subtitle.add_css_class("dim-label")
        username = Gtk.Entry()
        username.set_placeholder_text("Username")
        password = Gtk.PasswordEntry()
        password.set_property("placeholder-text", "Password")
        password.set_show_peek_icon(True)
        status = Gtk.Label(label="", xalign=0)
        status.set_wrap(True)
        status.add_css_class("dim-label")
        button = Gtk.Button(label="Sign in")
        button.add_css_class("suggested-action")
        logout = Gtk.Button(label="Sign out")
        logout.set_visible(False)
        sync = Gtk.CheckButton(label="Sync bookmarks and settings")
        sync.set_active(self.store.setting("sync_enabled", "true") == "true")
        box.append(title)
        box.append(subtitle)
        box.append(username)
        box.append(password)
        box.append(status)
        box.append(button)
        box.append(logout)
        box.append(sync)

        def set_busy(busy: bool) -> None:
            button.set_sensitive(not busy)
            username.set_sensitive(not busy)
            password.set_sensitive(not busy)
            status.set_text("Connecting…" if busy else status.get_text())

        def finish_login(name: str | None, error: str | None) -> bool:
            set_busy(False)
            if error:
                status.set_text(error)
                status.add_css_class("error")
                return False
            status.remove_css_class("error")
            title.set_text(name or "tails1154 account")
            subtitle.set_text("Connected to tails1154.com")
            status.set_text("Signed in. Session is kept in memory only.")
            username.set_visible(False)
            password.set_visible(False)
            button.set_visible(False)
            logout.set_visible(True)
            password.set_text("")
            self.account_name = name
            self.sync_account(status)
            return False

        def login(*_args) -> None:
            name = username.get_text().strip()
            secret = password.get_text()
            set_busy(True)

            def worker() -> None:
                try:
                    account_name = self.account_client.login(name, secret)
                except Exception as error:
                    GLib.idle_add(finish_login, None, str(error))
                else:
                    GLib.idle_add(finish_login, account_name, None)

            threading.Thread(target=worker, daemon=True).start()

        def finish_logout(error: str | None) -> bool:
            set_busy(False)
            if error:
                status.set_text(error)
                return False
            title.set_text("tails1154 account")
            subtitle.set_text("Sign in to tails1154.com")
            status.set_text("Signed out.")
            username.set_visible(True)
            password.set_visible(True)
            button.set_visible(True)
            logout.set_visible(False)
            self.account_name = None
            return False

        def sign_out(*_args) -> None:
            logout.set_sensitive(False)

            def worker() -> None:
                try:
                    self.account_client.logout()
                except Exception as error:
                    GLib.idle_add(finish_logout, str(error))
                else:
                    GLib.idle_add(finish_logout, None)
                GLib.idle_add(logout.set_sensitive, True)

            threading.Thread(target=worker, daemon=True).start()

        button.connect("clicked", login)
        password.connect("activate", login)
        logout.connect("clicked", sign_out)

        def sync_changed(check: Gtk.CheckButton) -> None:
            enabled = check.get_active()
            self.store.set_setting("sync_enabled", "true" if enabled else "false")
            if enabled and self.account_name:
                self.sync_account(status)

        sync.connect("toggled", sync_changed)
        popover.set_child(box)

        def restore_session() -> None:
            try:
                name = self.account_client.username()
            except Exception:
                return
            if name:
                GLib.idle_add(finish_login, name, None)

        threading.Thread(target=restore_session, daemon=True).start()
        return popover

    def _install_shortcuts(self) -> None:
        controller = Gtk.ShortcutController()
        controller.set_scope(Gtk.ShortcutScope.GLOBAL)
        shortcuts = {
            "<Control>l": self.focus_address,
            "<Control>t": self.new_tab,
            "<Control>w": self.close_current_tab,
            "<Control>d": self.toggle_bookmark,
            "<Control>h": self.show_history,
            "<Control><Shift>b": self.show_bookmarks,
            "<Control><Shift>a": self.show_ai,
            "<Control>comma": self.show_settings,
            "<Control><Shift>f": self.toggle_focus_mode,
            "<Alt>Left": lambda: self.current_view().go_back(),
            "<Alt>Right": lambda: self.current_view().go_forward(),
        }
        for accelerator, callback in shortcuts.items():
            trigger = Gtk.ShortcutTrigger.parse_string(accelerator)
            action = Gtk.CallbackAction.new(lambda _widget, _args, cb=callback: self._run(cb))
            controller.add_shortcut(Gtk.Shortcut.new(trigger, action))
        self.add_controller(controller)

    @staticmethod
    def _run(callback) -> bool:
        callback()
        return True

    def current_view(self):
        page = self.notebook.get_nth_page(self.notebook.get_current_page())
        return page

    def new_tab(self, uri: str = "trowser://homepage") -> None:
        view = WebKit.WebView()
        view.set_hexpand(True)
        view.set_vexpand(True)
        settings = view.get_settings()
        settings.set_enable_javascript(True)
        settings.set_enable_developer_extras(True)

        label_box = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=5)
        label = Gtk.Label(label="New tab")
        label.set_max_width_chars(22)
        label.set_ellipsize(3)
        close = icon_button("window-close-symbolic", "Close tab")
        label_box.append(label)
        label_box.append(close)

        index = self.notebook.append_page(view, label_box)
        self.notebook.set_tab_reorderable(view, True)
        self.notebook.set_current_page(index)
        close.connect("clicked", lambda *_: self.close_tab(view))
        view.connect("notify::title", self._view_title_changed, label)
        view.connect("notify::uri", self._view_uri_changed)
        view.connect("notify::estimated-load-progress", self._load_progress)
        view.connect("load-changed", self._load_changed)
        view.connect("create", self._create_webview)
        self.load(uri, view)

    def close_tab(self, view) -> None:
        page = self.notebook.page_num(view)
        if page >= 0:
            self.notebook.remove_page(page)
        if self.notebook.get_n_pages() == 0:
            self.new_tab()

    def close_current_tab(self) -> None:
        self.close_tab(self.current_view())

    def load(self, value: str, view=None) -> None:
        view = view or self.current_view()
        search_url = self.store.setting(
            "search_url", "https://duckduckgo.com/?q={}"
        )
        uri = address_to_uri(value, search_url)
        if uri == "trowser://homepage":
            view.load_html(HOME_HTML, "https://trowser.local/")
        else:
            view.load_uri(uri)

    def _address_activated(self, entry: Gtk.Entry) -> None:
        self.load(entry.get_text())
        self.current_view().grab_focus()

    def focus_address(self) -> None:
        if self.focus_mode:
            self.toggle_focus_mode()
        self.address.grab_focus()
        self.address.select_region(0, -1)

    def _view_title_changed(self, view, _param, label: Gtk.Label) -> None:
        title = view.get_title() or "New tab"
        label.set_text(title)
        if view is self.current_view():
            self.set_title(f"{title} — Trowser")

    def _view_uri_changed(self, view, _param) -> None:
        if view is self.current_view():
            self.address.set_text(display_uri(view.get_uri()))
            self._update_navigation()

    def _load_progress(self, view, _param) -> None:
        if view.get_estimated_load_progress() < 1:
            self.address.set_progress_fraction(view.get_estimated_load_progress())
        else:
            self.address.set_progress_fraction(0)

    def _load_changed(self, view, event) -> None:
        if event == WebKit.LoadEvent.FINISHED:
            uri = view.get_uri() or ""
            title = view.get_title() or uri
            self.store.add_history(uri, title)
            if view is self.current_view():
                self._update_navigation()

    def _tab_switched(self, _notebook, view, _index) -> None:
        if view:
            self.address.set_text(display_uri(view.get_uri()))
            self.set_title(f"{view.get_title() or 'New tab'} — Trowser")
            self._update_navigation()

    def _update_navigation(self) -> None:
        view = self.current_view()
        self.back.set_sensitive(view.can_go_back())
        self.forward.set_sensitive(view.can_go_forward())
        uri = view.get_uri() or ""
        starred = self.store.is_bookmarked(uri)
        self.bookmark.set_icon_name(
            "starred-symbolic" if starred else "non-starred-symbolic"
        )

    def _create_webview(self, _view, _action):
        self.new_tab()
        return self.current_view()

    def toggle_bookmark(self) -> None:
        view = self.current_view()
        uri = view.get_uri() or ""
        if not uri.startswith(("http://", "https://")):
            return
        if self.store.is_bookmarked(uri):
            self.store.remove_bookmark(uri)
        else:
            self.store.add_bookmark(uri, view.get_title() or uri)
        self._update_navigation()
        self.push_sync()

    def _clear_sidebar(self, title: str) -> None:
        while child := self.sidebar_box.get_first_child():
            self.sidebar_box.remove(child)
        header = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL)
        heading = Gtk.Label(label=title, xalign=0)
        heading.set_hexpand(True)
        heading.add_css_class("sidebar-title")
        close = icon_button("window-close-symbolic", "Close sidebar")
        close.connect("clicked", lambda *_: self.hide_sidebar())
        header.append(heading)
        header.append(close)
        self.sidebar_box.append(header)

    def _show_library(self, mode: str) -> None:
        self._clear_sidebar("Library")
        switcher = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=6)
        bookmarks = Gtk.Button(label="Bookmarks")
        history = Gtk.Button(label="History")
        bookmarks.connect("clicked", lambda *_: self.show_bookmarks())
        history.connect("clicked", lambda *_: self.show_history())
        switcher.append(bookmarks)
        switcher.append(history)
        self.sidebar_box.append(switcher)

        scroller = Gtk.ScrolledWindow()
        scroller.set_vexpand(True)
        items = Gtk.ListBox()
        items.set_selection_mode(Gtk.SelectionMode.NONE)
        records = self.store.bookmarks() if mode == "bookmarks" else self.store.history()
        if not records:
            empty = Gtk.Label(label=f"No {mode} yet.")
            empty.set_margin_top(30)
            empty.add_css_class("dim-label")
            items.append(empty)
        for record in records:
            row = Gtk.Button()
            row.add_css_class("flat")
            text = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=2)
            title = Gtk.Label(label=record["title"], xalign=0)
            title.set_ellipsize(3)
            url = Gtk.Label(label=record["url"], xalign=0)
            url.set_ellipsize(3)
            url.add_css_class("dim-label")
            text.append(title)
            text.append(url)
            row.set_child(text)
            row.connect("clicked", lambda _b, uri=record["url"]: self._open_sidebar_uri(uri))
            items.append(row)
        scroller.set_child(items)
        self.sidebar_box.append(scroller)
        if mode == "history" and records:
            clear = Gtk.Button(label="Clear history")
            clear.add_css_class("destructive-action")
            clear.connect("clicked", lambda *_: (self.store.clear_history(), self.show_history()))
            self.sidebar_box.append(clear)
        self.show_sidebar()

    def show_bookmarks(self) -> None:
        self._show_library("bookmarks")

    def show_history(self) -> None:
        self._show_library("history")

    def _open_sidebar_uri(self, uri: str) -> None:
        self.load(uri)
        self.hide_sidebar()

    def show_ai(self) -> None:
        self._clear_sidebar("Ollama")
        status = Gtk.Label(label="Checking local models…", xalign=0)
        status.add_css_class("dim-label")
        self.sidebar_box.append(status)

        model = Gtk.DropDown.new_from_strings(["Loading…"])
        self.sidebar_box.append(model)

        conversation = Gtk.TextView()
        conversation.set_editable(False)
        conversation.set_wrap_mode(Gtk.WrapMode.WORD_CHAR)
        conversation.set_left_margin(10)
        conversation.set_right_margin(10)
        scroller = Gtk.ScrolledWindow()
        scroller.set_vexpand(True)
        scroller.set_child(conversation)
        self.sidebar_box.append(scroller)

        context = Gtk.CheckButton(label="Include text from current page")
        context.set_active(True)
        self.sidebar_box.append(context)

        prompt = Gtk.TextView()
        prompt.set_wrap_mode(Gtk.WrapMode.WORD_CHAR)
        prompt.set_size_request(-1, 90)
        prompt.set_top_margin(8)
        prompt.set_left_margin(8)
        prompt.set_right_margin(8)
        self.sidebar_box.append(prompt)
        send = Gtk.Button(label="Ask Ollama")
        send.add_css_class("suggested-action")
        self.sidebar_box.append(send)
        self.show_sidebar()

        def models_ready(models: list[str]) -> bool:
            values = models or ["No models found"]
            model.set_model(Gtk.StringList.new(values))
            model.set_selected(0)
            status.set_text(
                "Runs locally through Ollama."
                if models
                else "Start Ollama and pull a model first."
            )
            send.set_sensitive(bool(models))
            return False

        threading.Thread(
            target=lambda: GLib.idle_add(models_ready, self.ollama.models()),
            daemon=True,
        ).start()

        def ask(*_args) -> None:
            buffer = prompt.get_buffer()
            text = buffer.get_text(buffer.get_start_iter(), buffer.get_end_iter(), True).strip()
            selected = model.get_selected_item()
            if not text or not selected or selected.get_string() == "No models found":
                return
            buffer.set_text("")
            output = conversation.get_buffer()
            output.set_text(f"You\n{text}\n\nOllama\nThinking…")
            send.set_sensitive(False)

            def run_with_context(page_text: str = "") -> None:
                answer = self.ollama.chat(selected.get_string(), text, page_text)

                def show_answer() -> bool:
                    output.set_text(f"You\n{text}\n\nOllama\n{answer}")
                    send.set_sensitive(True)
                    return False

                threading.Thread(
                    target=lambda: GLib.idle_add(show_answer), daemon=True
                ).start()

            if context.get_active():
                script = "document.body ? document.body.innerText : ''"

                def script_done(view, result) -> None:
                    try:
                        value = view.evaluate_javascript_finish(result)
                        page_text = value.to_string() if value else ""
                    except GLib.Error:
                        page_text = ""
                    threading.Thread(
                        target=run_with_context, args=(page_text,), daemon=True
                    ).start()

                self.current_view().evaluate_javascript(
                    script, -1, None, None, None, script_done
                )
            else:
                threading.Thread(target=run_with_context, daemon=True).start()

        send.connect("clicked", ask)

    def show_settings(self) -> None:
        self._clear_sidebar("Settings")

        search_label = Gtk.Label(label="Search engine", xalign=0)
        search_label.add_css_class("heading")
        self.sidebar_box.append(search_label)
        search = Gtk.DropDown.new_from_strings(["DuckDuckGo", "Google", "Bing"])
        search_urls = [
            "https://duckduckgo.com/?q={}",
            "https://www.google.com/search?q={}",
            "https://www.bing.com/search?q={}",
        ]
        current_search = self.store.setting("search_url", search_urls[0])
        search.set_selected(
            search_urls.index(current_search) if current_search in search_urls else 0
        )
        self.sidebar_box.append(search)

        ollama_label = Gtk.Label(label="Ollama endpoint", xalign=0)
        ollama_label.add_css_class("heading")
        self.sidebar_box.append(ollama_label)
        ollama_endpoint = Gtk.Entry()
        ollama_endpoint.set_text(
            self.store.setting("ollama_endpoint", "http://127.0.0.1:11434")
        )
        self.sidebar_box.append(ollama_endpoint)

        sync = Gtk.CheckButton(label="Sync bookmarks and settings")
        sync.set_active(self.store.setting("sync_enabled", "true") == "true")
        self.sidebar_box.append(sync)

        passwords = Gtk.Button(label="Open password manager")
        passwords.connect("clicked", lambda *_: self.show_passwords())
        self.sidebar_box.append(passwords)

        save = Gtk.Button(label="Save settings")
        save.add_css_class("suggested-action")
        self.sidebar_box.append(save)
        status = Gtk.Label(label="", xalign=0)
        status.add_css_class("dim-label")
        self.sidebar_box.append(status)

        def save_settings(*_args) -> None:
            self.store.set_setting("search_url", search_urls[search.get_selected()])
            endpoint = ollama_endpoint.get_text().strip().rstrip("/")
            if endpoint:
                self.store.set_setting("ollama_endpoint", endpoint)
                self.ollama.endpoint = endpoint
            self.store.set_setting(
                "sync_enabled", "true" if sync.get_active() else "false"
            )
            self.push_sync()
            status.set_text("Settings saved.")

        save.connect("clicked", save_settings)
        self.show_sidebar()

    def show_passwords(self) -> None:
        self._clear_sidebar("Passwords")
        if not self.vault.unlocked:
            explanation = Gtk.Label(
                label=(
                    "Enter your master password to unlock the vault."
                    if self.vault.exists
                    else "Create a master password (minimum 8 characters). "
                    "It cannot be recovered."
                ),
                xalign=0,
            )
            explanation.set_wrap(True)
            master = Gtk.PasswordEntry()
            master.set_property("placeholder-text", "Master password")
            master.set_show_peek_icon(True)
            unlock = Gtk.Button(
                label="Unlock vault" if self.vault.exists else "Create vault"
            )
            unlock.add_css_class("suggested-action")
            status = Gtk.Label(label="", xalign=0)
            status.set_wrap(True)
            self.sidebar_box.append(explanation)
            self.sidebar_box.append(master)
            self.sidebar_box.append(unlock)
            self.sidebar_box.append(status)

            def do_unlock(*_args) -> None:
                try:
                    self.vault.unlock(master.get_text())
                except VaultError as error:
                    status.set_text(str(error))
                    return
                master.set_text("")
                self.show_passwords()

            unlock.connect("clicked", do_unlock)
            master.connect("activate", do_unlock)
            self.show_sidebar()
            return

        site = Gtk.Entry()
        site.set_placeholder_text("Website")
        username = Gtk.Entry()
        username.set_placeholder_text("Username")
        password = Gtk.PasswordEntry()
        password.set_property("placeholder-text", "Password")
        password.set_show_peek_icon(True)
        add = Gtk.Button(label="Save password")
        add.add_css_class("suggested-action")
        for widget in (site, username, password, add):
            self.sidebar_box.append(widget)

        scroller = Gtk.ScrolledWindow()
        scroller.set_vexpand(True)
        entries = Gtk.ListBox()
        entries.set_selection_mode(Gtk.SelectionMode.NONE)
        for entry in self.vault.entries():
            row = Gtk.Box(orientation=Gtk.Orientation.HORIZONTAL, spacing=6)
            text = Gtk.Box(orientation=Gtk.Orientation.VERTICAL, spacing=2)
            text.set_hexpand(True)
            text.append(Gtk.Label(label=entry["site"], xalign=0))
            detail = Gtk.Label(label=entry["username"] or "(no username)", xalign=0)
            detail.add_css_class("dim-label")
            text.append(detail)
            copy = icon_button("edit-copy-symbolic", "Copy password")
            delete = icon_button("user-trash-symbolic", "Delete password")
            copy.connect(
                "clicked",
                lambda _b, secret=entry["password"]: Gdk.Display.get_default()
                .get_clipboard()
                .set(secret),
            )
            delete.connect(
                "clicked",
                lambda _b, entry_id=entry["id"]: (
                    self.vault.remove(entry_id),
                    self.show_passwords(),
                ),
            )
            row.append(text)
            row.append(copy)
            row.append(delete)
            entries.append(row)
        scroller.set_child(entries)
        self.sidebar_box.append(scroller)
        lock = Gtk.Button(label="Lock vault")
        lock.connect("clicked", lambda *_: (self.vault.lock(), self.show_passwords()))
        self.sidebar_box.append(lock)

        def add_password(*_args) -> None:
            try:
                self.vault.add(
                    site.get_text().strip(),
                    username.get_text(),
                    password.get_text(),
                )
            except VaultError:
                return
            self.show_passwords()

        add.connect("clicked", add_password)
        password.connect("activate", add_password)
        self.show_sidebar()

    def toggle_focus_mode(self) -> None:
        self.focus_mode = not self.focus_mode
        self.store.set_setting("focus_mode", "true" if self.focus_mode else "false")
        self.toolbar.set_visible(not self.focus_mode)
        self.notebook.set_show_tabs(not self.focus_mode)
        if self.focus_mode:
            self.hide_sidebar()

    def show_sidebar(self) -> None:
        self.sidebar.set_visible(True)
        self.sidebar.set_reveal_child(True)

    def hide_sidebar(self) -> None:
        self.sidebar.set_reveal_child(False)

    def _sidebar_transition_done(self, revealer: Gtk.Revealer, _param) -> None:
        if not revealer.get_child_revealed() and not revealer.get_reveal_child():
            revealer.set_visible(False)

    def _sync_document(self) -> dict:
        bookmarks = [
            {"url": item["url"], "title": item["title"]}
            for item in self.store.bookmarks()
        ]
        settings = self.store.settings()
        settings.pop("focus_mode", None)
        return {"version": 1, "bookmarks": bookmarks, "settings": settings}

    def sync_account(self, status: Gtk.Label | None = None) -> None:
        if (
            not self.account_name
            or self.store.setting("sync_enabled", "true") != "true"
        ):
            return
        local = self._sync_document()
        if status:
            status.set_text("Syncing bookmarks and settings…")

        def worker() -> None:
            try:
                remote = self.account_client.load_sync()
                remote_bookmarks = remote.get("bookmarks", [])
                remote_settings = remote.get("settings", {})
                if not isinstance(remote_bookmarks, list):
                    remote_bookmarks = []
                if not isinstance(remote_settings, dict):
                    remote_settings = {}
                merged = {
                    "version": 1,
                    "bookmarks": list(
                        {
                            item["url"]: item
                            for item in local["bookmarks"] + remote_bookmarks
                            if isinstance(item, dict) and item.get("url")
                        }.values()
                    ),
                    "settings": {**local["settings"], **remote_settings},
                }
                self.account_client.save_sync(merged)
            except Exception as error:
                if status:
                    GLib.idle_add(status.set_text, f"Sync failed: {error}")
                return

            def apply() -> bool:
                self.store.merge_bookmarks(merged["bookmarks"])
                self.store.merge_settings(merged["settings"])
                self.ollama.endpoint = self.store.setting(
                    "ollama_endpoint", "http://127.0.0.1:11434"
                )
                if status:
                    status.set_text("Bookmarks and settings are synced.")
                return False

            GLib.idle_add(apply)

        threading.Thread(target=worker, daemon=True).start()

    def push_sync(self) -> None:
        if (
            not self.account_name
            or self.store.setting("sync_enabled", "true") != "true"
        ):
            return
        document = self._sync_document()

        def worker() -> None:
            try:
                self.account_client.save_sync(document)
            except Exception:
                pass

        threading.Thread(target=worker, daemon=True).start()

    def _on_close(self, _window) -> bool:
        self.vault.lock()
        self.store.close()
        return False


class TrowserApplication(Gtk.Application):
    def __init__(self) -> None:
        super().__init__(
            application_id="io.github.tails1154.Trowser",
            flags=Gio.ApplicationFlags.DEFAULT_FLAGS,
        )

    def do_startup(self) -> None:
        Gtk.Application.do_startup(self)
        css = Gtk.CssProvider()
        css.load_from_path(str(Path(__file__).with_name("style.css")))
        Gtk.StyleContext.add_provider_for_display(
            Gdk.Display.get_default(), css, Gtk.STYLE_PROVIDER_PRIORITY_APPLICATION
        )

    def do_activate(self) -> None:
        window = self.get_active_window()
        if not window:
            window = TrowserWindow(self)
        window.present()


def main() -> int:
    if WebKit is None:
        print(
            "Trowser needs the WebKitGTK 6.0 Python GI namespace.\n"
            f"Import error: {WEBKIT_ERROR}\n"
            "See README.md for distribution package examples.",
            file=sys.stderr,
        )
        return 1
    return TrowserApplication().run(sys.argv)
